4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell due to underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells due to underpopulation", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged as a still life", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
18	  });
19	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
20	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
21	    expect(result).toHaveLength(3);
